#!/usr/bin/env bash
# UserPromptSubmit hook — injects model routing mandate as additionalContext on every turn.
printf '%s' '{"hookSpecificOutput":{"hookEventName":"UserPromptSubmit","additionalContext":"MODEL ROUTING MANDATE (permissions.deny blocks opus — verified):\n🟢 haiku: file edits, renames, search/grep, bash one-liners, format fixes, config changes, adding imports, boilerplate, anything where correct output is exact-match checkable. DEFAULT for leaf work.\n🔵 sonnet: code synthesis, debugging, error-handling, API logic, review, refactoring, anything needing judgment.\n🔵 sonnet lead: orchestration, multi-step plans, adversarial verify, launchd/git mutations, wave gates.\nRULES: (1) Agent(model:opus) is hard-denied. (2) Unspecified model = sonnet. (3) ALWAYS lean haiku for leaf tasks — if in doubt between haiku and sonnet, pick haiku and escalate only if it fails. (4) Set model: explicitly on every Agent call."}}'
